import{_ as a,o as t,c as r,ag as s}from"./chunks/framework.DXGyWiRo.js";const d=JSON.parse('{"title":"Starting a Game Session","description":"","frontmatter":{},"headers":[],"relativePath":"scoring-games/starting-a-game.md","filePath":"scoring-games/starting-a-game.md"}'),i={name:"scoring-games/starting-a-game.md"};function o(n,e,l,m,c,g){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="starting-a-game-session" tabindex="-1">Starting a Game Session <a class="header-anchor" href="#starting-a-game-session" aria-label="Permalink to &quot;Starting a Game Session&quot;">​</a></h1><h2 id="before-the-first-pitch" tabindex="-1">Before the First Pitch <a class="header-anchor" href="#before-the-first-pitch" aria-label="Permalink to &quot;Before the First Pitch&quot;">​</a></h2><ol><li>From the dashboard tap <strong>Log Game Data</strong></li><li>Select <strong>Game</strong> as the session type</li><li>Select your opponent — choose from your saved opponents list or tap <strong>New Opponent</strong> to add one</li><li>If you have a game scheduled for today it will appear at the top as a pre-filled option — select it to avoid re-entering details</li><li>Confirm the date and location</li><li>Tap <strong>Start Game</strong></li></ol><p>The Game Hub opens and the session is active. An amber active game banner will appear on all other screens until the game is ended.</p><h2 id="pre-game-checklist" tabindex="-1">Pre-Game Checklist <a class="header-anchor" href="#pre-game-checklist" aria-label="Permalink to &quot;Pre-Game Checklist&quot;">​</a></h2><p>Before the first pitch confirm:</p><ul><li>Correct opponent is selected</li><li>Correct date shows (important for retroactive scoring)</li><li>Your roster is up to date — add any new players before starting</li><li>Any scorekeeper helpers are logged in and have the app open</li></ul><h2 id="scrimmage-vs-game" tabindex="-1">Scrimmage vs. Game <a class="header-anchor" href="#scrimmage-vs-game" aria-label="Permalink to &quot;Scrimmage vs. Game&quot;">​</a></h2><p>When starting a session you select the session type:</p><ul><li><strong>Game</strong> — counts toward season records, win/loss, ERA, and all analytics</li><li><strong>Scrimmage</strong> — logged identically but filtered separately in analytics</li></ul><p>Use Scrimmage for intra-squad games or unofficial opponents. The event type filter in analytics lets you compare game vs scrimmage performance.</p><h2 id="resuming-an-interrupted-session" tabindex="-1">Resuming an Interrupted Session <a class="header-anchor" href="#resuming-an-interrupted-session" aria-label="Permalink to &quot;Resuming an Interrupted Session&quot;">​</a></h2><p>If you navigate away mid-game the session stays active. Return to it via:</p><ul><li>The <strong>amber active game banner</strong> at the top of any screen</li><li>The <strong>Resume</strong> button on the game card in your schedule</li><li>The <strong>Live Game widget</strong> on your dashboard</li></ul>',14)])])}const p=a(i,[["render",o]]);export{d as __pageData,p as default};
